 2	import classNames from 'classnames';
 3	
 4	import { ListItem, Split, SplitItem } from '@patternfly/react-core';
 5	
 6	import { INSTANCE_TYPES_SECTIONS } from '../../utils/constants';
 7	
 8	type SectionListItemProps = {
 9	  headerAction?: ReactNode;
10	  headerText: ReactNode;
11	  sectionKey: INSTANCE_TYPES_SECTIONS;
12	  sectionState: [INSTANCE_TYPES_SECTIONS, Dispatch<SetStateAction<INSTANCE_TYPES_SECTIONS>>];
13	};
